    from collections import defaultdict, deque

    g = np.array(grid)
    H, W = g.shape

    # Find background color (most common)
    flat = g.flatten()
    bg = int(np.bincount(flat).argmax())

    # Find all L-shapes (2x2 blocks with one corner = bg)
    l_shapes = []
    for r in range(H-1):
        for c in range(W-1):
            block = g[r:r+2, c:c+2]
            cells = []
            bg_cells = []
            colors = set()
            for dr in range(2):
                for dc in range(2):
                    v = int(block[dr, dc])
                    if v == bg:
                        bg_cells.append((r+dr, c+dc))
                    else:
                        cells.append((r+dr, c+dc))
                        colors.add(v)
            if len(bg_cells) == 1 and len(colors) == 1:
                color = colors.pop()
                missing = bg_cells[0]
                mr, mc = missing[0]-r, missing[1]-c
                corner_type = mr*2 + mc  # 0=TL, 1=TR, 2=BL, 3=BR missing
                l_shapes.append((color, tuple(sorted(cells)), corner_type, (r, c)))

    # Group by color
    shapes_by_color = defaultdict(list)
    for color, cells, corner, pos in l_shapes:
        shapes_by_color[color].append((cells, corner, pos))

    # Pair L-shapes and compute rectangles
    l_shape_cells_set = set()  # All cells that are part of L-shapes
    pairs = {}  # color -> (l1_cells, l2_cells, rect)

    for color, shape_list in shapes_by_color.items():
        if len(shape_list) != 2:
            continue
        s1, s2 = shape_list
        cells1, corner1, pos1 = s1
        cells2, corner2, pos2 = s2

        # Check compatibility: BR(3)+TL(0) or BL(2)+TR(1)
        if {corner1, corner2} == {0, 3} or {corner1, corner2} == {1, 2}:
            # Compute bounding rectangle
            all_cells = list(cells1) + list(cells2)
            min_r = min(r for r, c in all_cells)
            max_r = max(r for r, c in all_cells)
            min_c = min(c for r, c in all_cells)
            max_c = max(c for r, c in all_cells)

            pairs[color] = (cells1, cells2, (min_r, max_r, min_c, max_c))
            for cell in all_cells:
                l_shape_cells_set.add(cell)

    # Find non-bg, non-L-shape cells
    other_cells = []
    for r in range(H):
        for c in range(W):
            v = int(g[r, c])
            if v != bg and (r, c) not in l_shape_cells_set:
                other_cells.append((r, c, v))

    # Find connected components of other_cells
    other_set = set((r, c) for r, c, v in other_cells)
    visited = set()
    components = []
    for r, c, v in other_cells:
        if (r, c) in visited:
            continue
        comp = []
        queue = deque([(r, c)])
        visited.add((r, c))
        while queue:
            cr, cc = queue.popleft()
            comp.append((cr, cc))
            for dr in [-1, 0, 1]:
                for dc in [-1, 0, 1]:
                    if dr == 0 and dc == 0:
                        continue
                    nr, nc = cr+dr, cc+dc
                    if (nr, nc) in other_set and (nr, nc) not in visited:
                        visited.add((nr, nc))
                        queue.append((nr, nc))
        components.append(comp)

    # Identify legend: the component that forms a 2-column structure
    # with shape colors in the left column
    legend_comp = None
    orphan_cells = []

    for comp in components:
        min_c = min(c for r, c in comp)
        max_c = max(c for r, c in comp)
        if max_c - min_c == 1:  # 2 columns wide
            legend_comp = comp
        else:
            orphan_cells.extend(comp)

    if legend_comp is None and len(components) == 1:
        # Maybe the legend is the only component (like example 0 where it's an L-shape)
        comp = components[0]
        min_c = min(c for r, c in comp)
        max_c = max(c for r, c in comp)
        if max_c - min_c <= 1:
            legend_comp = comp

    # Parse legend
    legend_map = {}
    if legend_comp:
        min_r = min(r for r, c in legend_comp)
        max_r = max(r for r, c in legend_comp)
        min_c = min(c for r, c in legend_comp)

        for r in range(min_r, max_r + 1):
            shape_color = int(g[r, min_c])
            fill_color = int(g[r, min_c + 1])
            if shape_color != bg:
                legend_map[shape_color] = fill_color

    # Determine fillable pairs
    all_rects = {color: rect for color, (_, _, rect) in pairs.items()}

    fillable = {}
    for color in pairs:
        if color not in legend_map:
            continue
        cells1, cells2, rect = pairs[color]

        # Find containers for each L-shape
        l1_containers = set()
        l2_containers = set()
        for other_color, other_rect in all_rects.items():
            if other_color == color:
                continue
            r1, r2, c1, c2 = other_rect
            if all(r1 <= r <= r2 and c1 <= c <= c2 for r, c in cells1):
                l1_containers.add(other_color)
            if all(r1 <= r <= r2 and c1 <= c <= c2 for r, c in cells2):
                l2_containers.add(other_color)

        # Fillable if at least one L is free, or both in same container
        if not l1_containers or not l2_containers:
            fillable[color] = True
        elif l1_containers & l2_containers:
            fillable[color] = True
        else:
            fillable[color] = False

    # Create output grid
    out = [row[:] for row in grid]

    # Fill rectangles from largest to smallest
    fill_order = sorted(
        [(color, pairs[color]) for color in fillable if fillable[color]],
        key=lambda x: (x[1][2][1]-x[1][2][0]+1) * (x[1][2][2]-x[1][2][2]+1),
        reverse=True
    )

    # Actually, sort by area (largest first)
    fill_order = sorted(
        [(color, pairs[color]) for color in fillable if fillable[color]],
        key=lambda x: (x[1][2][1]-x[1][2][0]+1) * (x[1][2][3]-x[1][2][2]+1),
        reverse=True
    )

    for color, (cells1, cells2, rect) in fill_order:
        r1, r2, c1, c2 = rect
        fill_color = legend_map[color]

        # Fill entire rectangle
        for r in range(r1, r2+1):
            for c in range(c1, c2+1):
                out[r][c] = fill_color

        # Restore L-shapes
        for r, c in cells1:
            out[r][c] = color
        for r, c in cells2:
            out[r][c] = color

    # Recolor orphan cells
    for r, c in orphan_cells:
        orig_color = int(g[r, c])
        if orig_color in legend_map:
            out[r][c] = legend_map[orig_color]

    return out

